import { Logger } from '@nestjs/common';

import { TABLE_NAME_STYLE_COPURCHASES } from '@constants/db.constant';

import type { Knex } from 'knex';

const logger = new Logger('20260216120000_create_style_copurchases_table.ts');

export async function up(knex: Knex): Promise<void> {
	logger.log('Creating style_copurchases table');

	await knex.transaction(async (trx) => {
		const tableExists = await trx.schema.hasTable(TABLE_NAME_STYLE_COPURCHASES);

		if (!tableExists) {
			await trx.schema.createTable(TABLE_NAME_STYLE_COPURCHASES, (table) => {
				table.uuid('_id').primary().notNullable();
				table.bigInteger('style_id_a').unsigned().notNullable();
				table.bigInteger('style_id_b').unsigned().notNullable();
				table.integer('copurchase_count').unsigned().notNullable().defaultTo(0);

				table.timestamp('created_at').defaultTo(trx.fn.now()).notNullable();
				table.timestamp('updated_at').defaultTo(trx.fn.now()).notNullable();
				table.timestamp('deleted_at').nullable();

				table.index(['style_id_a', 'deleted_at', 'copurchase_count']);
				table.index(['style_id_b', 'deleted_at', 'copurchase_count']);

				table.unique(['style_id_a', 'style_id_b'], {
					predicate: trx.whereNull('deleted_at'),
				});
			});

			logger.log('Successfully created style_copurchases table');
		} else {
			logger.log('style_copurchases table already exists, skipping');
		}
	});
}

export async function down(knex: Knex): Promise<void> {
	logger.log('Dropping style_copurchases table');

	await knex.transaction(async (trx) => {
		await trx.schema.dropTableIfExists(TABLE_NAME_STYLE_COPURCHASES);
	});
}

